import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import {
  StatsCard,
  StatsCardsGrid,
  Card,
  TableCard,
  Badge,
  Button,
} from '@linm-soft-org/linm-web-common-components';
import {
  Bar,
  BarChart,
  CartesianGrid,
  Cell,
  Legend,
  Pie,
  PieChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import { fpcService } from '../../../services/fpc/service';
import type { CeoTodayForecastDto, BranchCashSummaryDto } from '../../../services/fpc/types';
import { useAppDispatch } from '../../../store/hooks';
import { dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import styles from './CeoCashTodayPage.module.css';

/* ── Constants ────────────────────────────────────────── */

const AUTO_REFRESH_MS = 5 * 60 * 1000; // 5 minutes
const TEST_ID = 'ceo-cash-today';

/* ── Formatters ─────────────────────────────────────────── */

const fVnd = (v: number): string =>
  new Intl.NumberFormat('vi-VN', {
    style: 'currency',
    currency: 'VND',
    maximumFractionDigits: 0,
  }).format(v);

const fVndCompact = (v: number): string => {
  if (v >= 1_000_000_000) return `${(v / 1_000_000_000).toFixed(1)} tỷ`;
  if (v >= 1_000_000) return `${(v / 1_000_000).toFixed(1)} tr`;
  return fVnd(v);
};

const fDate = (iso: string): string => {
  try {
    return new Date(iso).toLocaleDateString('vi-VN', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
    });
  } catch {
    return iso;
  }
};

/* ── Helpers ────────────────────────────────────────────── */

const daysUntil = (iso: string): number => {
  const now = new Date();
  const target = new Date(iso);
  const diff = target.getTime() - now.getTime();
  return Math.ceil(diff / (1000 * 60 * 60 * 24));
};

const CHART_TOOLTIP = (v: number) => fVnd(v);

const DAY_LABELS = ['CN', 'T2', 'T3', 'T4', 'T5', 'T6', 'T7'];
const dayLabel = (iso: string): string => {
  try {
    return DAY_LABELS[new Date(iso).getDay()];
  } catch {
    return iso;
  }
};

const severityToAlertStyle = (severity: string): 'red' | 'yellow' | 'green' => {
  if (severity === 'Critical') return 'red';
  if (severity === 'Warning') return 'yellow';
  return 'green';
};

const severityIcon = (severity: string): string => {
  if (severity === 'Critical') return 'fas fa-exclamation-circle';
  if (severity === 'Warning') return 'fas fa-exclamation-triangle';
  return 'fas fa-check-circle';
};

/* ── Sub-components ───────────────────────────────────── */

interface AlertItem {
  severity: 'red' | 'yellow' | 'green';
  title: string;
  message: string;
  date: string;
}

const AlertItemRow: React.FC<{ alert: AlertItem }> = ({ alert }) => {
  const severityClass =
    alert.severity === 'red'
      ? styles.alertRed
      : alert.severity === 'yellow'
        ? styles.alertYellow
        : styles.alertGreen;
  const iconClass = severityIcon(
    alert.severity === 'red' ? 'Critical' : alert.severity === 'yellow' ? 'Warning' : 'Info',
  );

  return (
    <div className={`${styles.alertItem} ${severityClass}`}>
      <div className={styles.alertIcon}>
        <i className={iconClass} />
      </div>
      <div className={styles.alertBody}>
        <div className={styles.alertHeader}>
          <span className={styles.alertTitle}>{alert.title}</span>
          <span className={styles.alertDate}>{alert.date}</span>
        </div>
        <p className={styles.alertMessage}>{alert.message}</p>
      </div>
    </div>
  );
};

/* ── Branch row component ─────────────────────────────── */

const BranchRow: React.FC<{
  branch: BranchCashSummaryDto;
  rank: number;
  isTop: boolean;
}> = ({ branch, rank, isTop }) => {
  const netLabel = branch.netCashflow >= 0 ? fVndCompact(branch.netCashflow) : `-${fVndCompact(Math.abs(branch.netCashflow))}`;
  return (
    <div className={styles.branchRow}>
      <div className={styles.branchRank}>
        <Badge variant={isTop ? 'success' : 'warning'} size="sm">
          #{rank}
        </Badge>
      </div>
      <div className={styles.branchInfo}>
        <span className={styles.branchName}>{branch.branchName}</span>
        <span className={styles.branchDetail}>
          Thu {fVndCompact(branch.expectedInflow)} / Chi {fVndCompact(branch.expectedOutflow)}
        </span>
      </div>
      <div className={`${styles.branchNet} ${branch.netCashflow >= 0 ? styles.netPositive : styles.netNegative}`}>
        {netLabel}
      </div>
    </div>
  );
};

/* ── Page component ─────────────────────────────────────── */

const CeoCashTodayPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [data, setData] = useState<CeoTodayForecastDto | null>(null);
  const [loading, setLoading] = useState(true);
  const [lastRefresh, setLastRefresh] = useState<Date>(new Date());
  const loadCountRef = useRef(0);

  const loadData = useCallback(async (showLoading: boolean) => {
    const loadId = ++loadCountRef.current;
    if (showLoading) setLoading(true);
    try {
      const result = await fpcService.getCeoToday({});
      if (loadCountRef.current === loadId) {
        setData(result);
        setLastRefresh(new Date());
      }
    } catch (err) {
      if (loadCountRef.current === loadId) {
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Không thể tải dữ liệu tiền mặt hôm nay.'),
          type: 'warning',
        });
      }
    } finally {
      if (loadCountRef.current === loadId) {
        if (showLoading) setLoading(false);
      }
    }
  }, [dispatch]);

  // Initial load + auto-refresh
  useEffect(() => {
    loadData(true);
    const interval = setInterval(() => loadData(false), AUTO_REFRESH_MS);
    return () => {
      clearInterval(interval);
      loadCountRef.current = -1;
    };
  }, [loadData]);

  const netCashflow = data ? data.expectedInflow - data.expectedOutflow : 0;
  const redDateDays = data?.nearestRedDate ? daysUntil(data.nearestRedDate) : null;
  const runwayDays = data?.runwayDays ?? 0;

  // ── KPI cards ──
  const kpiCards = useMemo(() => {
    if (!data) return null;
    const redDateVariant = redDateDays !== null && redDateDays <= 7 ? 'danger' : 'warning';
    return (
      <StatsCardsGrid columns={4}>
        <StatsCard
          label="Tổng tiền mặt"
          value={fVndCompact(data.totalCash)}
          icon="fas fa-money-bill-wave"
          variant="total"
        />
        <StatsCard
          label="Tiền khả dụng"
          value={fVndCompact(data.availableCash)}
          icon="fas fa-hand-holding-usd"
          variant="primary"
        />
        <StatsCard
          label="Số ngày an toàn"
          value={runwayDays >= 999 ? '> 30 ngày' : `${runwayDays} ngày`}
          icon="fas fa-shield-alt"
          variant={runwayDays <= 7 ? 'danger' : runwayDays <= 14 ? 'warning' : 'success'}
        />
        <StatsCard
          label="Ngày đỏ gần nhất"
          value={data.nearestRedDate ? fDate(data.nearestRedDate) : '—'}
          icon="fas fa-calendar-exclamation"
          variant={redDateDays !== null ? redDateVariant : 'success'}
        />
      </StatsCardsGrid>
    );
  }, [data, redDateDays, runwayDays]);

  // ── Today's cashflow cards ──
  const cashflowCards = useMemo(() => {
    if (!data) return null;
    return (
      <StatsCardsGrid columns={4}>
        <StatsCard
          label="Số dư đầu ngày"
          value={fVndCompact(data.openingBalance)}
          icon="fas fa-coins"
          variant="info"
        />
        <StatsCard
          label="Thu trong ngày"
          value={fVndCompact(data.expectedInflow)}
          icon="fas fa-arrow-down"
          variant="success"
        />
        <StatsCard
          label="Chi trong ngày"
          value={fVndCompact(data.expectedOutflow)}
          icon="fas fa-arrow-up"
          variant="warning"
        />
        <StatsCard
          label="Dòng tiền thuần"
          value={`${netCashflow >= 0 ? '+' : ''}${fVndCompact(netCashflow)}`}
          icon={netCashflow >= 0 ? 'fas fa-arrow-trend-up' : 'fas fa-arrow-trend-down'}
          variant={netCashflow >= 0 ? 'success' : 'danger'}
        />
      </StatsCardsGrid>
    );
  }, [data, netCashflow]);

  // ── 7-day trend chart ──
  const trendChart = useMemo(() => {
    if (!data || data.next7Days.length === 0) return null;
    const chartData = data.next7Days.map(d => ({
      label: dayLabel(d.date),
      ...d,
    }));
    return (
      <Card padding="md" className={styles.chartCard} data-testid={`${TEST_ID}-trend-chart`}>
        <div className={styles.chartCardHeader}>
          <h3 className={styles.chartTitle}>Dự kiến 7 ngày tới</h3>
          <Badge variant="info" size="sm">Thu / Chi theo ngày</Badge>
        </div>
        <ResponsiveContainer width="100%" height={260}>
          <BarChart data={chartData}>
            <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
            <XAxis dataKey="label" tick={{ fontSize: 12 }} />
            <YAxis tickFormatter={v => `${(Number(v) / 1e6).toFixed(0)}M`} tick={{ fontSize: 12 }} />
            <Tooltip formatter={CHART_TOOLTIP} />
            <Legend />
            <Bar dataKey="inflow" name="Thu" fill="#52c41a" radius={[4, 4, 0, 0]} />
            <Bar dataKey="outflow" name="Chi" fill="#fa8c16" radius={[4, 4, 0, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </Card>
    );
  }, [data]);

  // ── Composition pie chart ──
  const compositionChart = useMemo(() => {
    if (!data) return null;
    return (
      <Card padding="md" className={styles.chartCard} data-testid={`${TEST_ID}-composition-chart`}>
        <div className={styles.chartCardHeader}>
          <h3 className={styles.chartTitle}>Cơ cấu thu/chi hôm nay</h3>
          <Badge variant="info" size="sm">Biểu đồ tròn</Badge>
        </div>
        <ResponsiveContainer width="100%" height={260}>
          <PieChart>
            <Pie
              data={data.composition}
              dataKey="value"
              nameKey="name"
              cx="50%"
              cy="50%"
              innerRadius={55}
              outerRadius={95}
              paddingAngle={3}
              label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
            >
              {data.composition.map(entry => (
                <Cell key={entry.name} fill={entry.color} />
              ))}
            </Pie>
            <Tooltip formatter={CHART_TOOLTIP} />
          </PieChart>
        </ResponsiveContainer>
        <div className={styles.legendRow}>
          {data.composition.map(entry => (
            <div key={entry.name} className={styles.legendItem}>
              <span className={styles.legendDot} style={{ background: entry.color }} />
              <span className={styles.legendLabel}>{entry.name}</span>
              <span className={styles.legendValue}>{fVndCompact(entry.value)}</span>
            </div>
          ))}
        </div>
      </Card>
    );
  }, [data]);

  // ── Top outflows table ──
  const topOutflows = useMemo(() => {
    if (!data || data.topOutflows.length === 0) return null;
    return (
      <TableCard
        header={
          <div className={styles.tableCardHeader}>
            <h3 className={styles.cardTitle}>Chi nhiều nhất hôm nay</h3>
            <span className={styles.cardSubtitle}>
              Tổng chi: {fVnd(data.expectedOutflow)}
            </span>
          </div>
        }
        tableCardTestId={`${TEST_ID}-top-outflows`}
      >
        <table className={styles.outflowTable}>
          <thead>
            <tr>
              <th>Danh mục</th>
              <th className={styles.colRight}>Số tiền</th>
              <th className={styles.colRight}>Tỷ trọng</th>
              <th className={styles.colBar} />
            </tr>
          </thead>
          <tbody>
            {data.topOutflows.map((item, i) => (
              <tr key={i}>
                <td>{item.category}</td>
                <td className={styles.colRight}>{fVnd(item.amount)}</td>
                <td className={styles.colRight}>{item.percent}%</td>
                <td className={styles.colBar}>
                  <div className={styles.barTrack}>
                    <div
                      className={styles.barFill}
                      style={{ width: `${Math.min(item.percent, 100)}%` }}
                    />
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </TableCard>
    );
  }, [data]);

  // ── Branch performance ──
  const branchSection = useMemo(() => {
    if (!data || data.branchSummaries.length === 0) return null;
    const sorted = [...data.branchSummaries].sort((a, b) => b.netCashflow - a.netCashflow);
    const top = sorted.slice(0, 3);
    const bottom = sorted.slice(-3).reverse();
    return (
      <Card padding="md" className={styles.branchCard} data-testid={`${TEST_ID}-branches`}>
        <div className={styles.branchCardHeader}>
          <h3 className={styles.cardTitle}>Hiệu suất chi nhánh</h3>
          <Badge variant="info" size="sm">{data.branchSummaries.length} CH</Badge>
        </div>
        <div className={styles.branchGrid}>
          <div className={styles.branchColumn}>
            <div className={styles.branchColumnTitle}>
              <i className="fas fa-arrow-trend-up" style={{ color: '#52c41a' }} />
              Top CH
            </div>
            {top.map((b, i) => (
              <BranchRow key={b.branchCode} branch={b} rank={i + 1} isTop />
            ))}
          </div>
          <div className={styles.branchDivider} />
          <div className={styles.branchColumn}>
            <div className={styles.branchColumnTitle}>
              <i className="fas fa-arrow-trend-down" style={{ color: '#fa8c16' }} />
              Cần cải thiện
            </div>
            {bottom.map((b, i) => (
              <BranchRow key={b.branchCode} branch={b} rank={sorted.length - i} isTop={false} />
            ))}
          </div>
        </div>
      </Card>
    );
  }, [data]);

  // ── Alerts card ──
  const alertsCard = useMemo(() => {
    if (!data) return null;
    const items: AlertItem[] = data.alerts.map(a => ({
      severity: severityToAlertStyle(a.severity),
      title: a.title,
      message: a.message,
      date: a.dateLabel ?? new Date(data.asOfDate).toLocaleDateString('vi-VN'),
    }));
    const criticalCount = data.alerts.filter(a => a.severity === 'Critical').length;
    return (
      <Card padding="none" className={styles.alertsCard} data-testid={`${TEST_ID}-alerts`}>
        <div className={styles.alertsCardHeader}>
          <h3 className={styles.cardTitle}>Cảnh báo và thông báo</h3>
          <div className={styles.alertsHeaderRight}>
            <Badge variant="danger" size="sm">
              {criticalCount} nghiêm trọng
            </Badge>
          </div>
        </div>
        <div className={styles.alertsList}>
          {items.map((alert, i) => (
            <AlertItemRow key={i} alert={alert} />
          ))}
        </div>
      </Card>
    );
  }, [data]);

  // ── Quick actions ──
  const quickActions = useMemo(() => {
    const goToForecast = () => {
      window.history.pushState(null, '', '/tc/kh/du-bao-tien-mat');
      window.dispatchEvent(new PopStateEvent('popstate'));
    };
    const goToCostPlan = () => {
      window.history.pushState(null, '', '/tc/kh/chi-phi-du-kien');
      window.dispatchEvent(new PopStateEvent('popstate'));
    };
    const goToPnl = () => {
      window.history.pushState(null, '', '/tc/bc/pnl-chi-nhanh');
      window.dispatchEvent(new PopStateEvent('popstate'));
    };
    return (
      <div className={styles.quickActions}>
        <Button variant="primary" size="md" onClick={goToForecast}>
          <i className="fas fa-chart-line" style={{ marginRight: 6 }} />
          Xem dự báo 14 ngày
        </Button>
        <Button variant="secondary" size="md" onClick={() => loadData(false)}>
          <i className="fas fa-sync-alt" style={{ marginRight: 6 }} />
          Làm mới
        </Button>
        <Button variant="secondary" size="md" onClick={goToCostPlan}>
          <i className="fas fa-copy" style={{ marginRight: 6 }} />
          Chi phí dự kiến
        </Button>
      </div>
    );
  }, [loadData]);

  // ── Loading state ──
  if (loading) {
    return (
      <div className={styles.page}>
        <div className={styles.pageHeader}>
          <div className={styles.titleBlock}>
            <h1 className={styles.title}>
              <i className="fas fa-chart-pie" />
              Tiền mặt hôm nay
            </h1>
            <p className={styles.subtitle}>Đang tải dữ liệu...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.page}>
      {/* ── Page header ── */}
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}>
            <i className="fas fa-chart-pie" />
            Tiền mặt hôm nay
          </h1>
          <p className={styles.subtitle}>
            Tổng quan tình hình tiền mặt &mdash;
            {data ? `Cập nhật: ${fDate(data.asOfDate)}` : ''}
            <span className={styles.refreshTime}>
              &nbsp;· Tự động làm mới mỗi 5 phút
            </span>
          </p>
        </div>
        <div className={styles.headerActions}>
          <Button variant="secondary" size="sm" onClick={() => loadData(false)}>
            <i className="fas fa-sync-alt" />
          </Button>
        </div>
      </div>

      {/* ── KPI Cards ── */}
      {kpiCards && (
        <section data-testid={`${TEST_ID}-kpi-row`}>
          {kpiCards}
        </section>
      )}

      {/* ── Today's Cashflow ── */}
      {data && (
        <section data-testid={`${TEST_ID}-cashflow-row`}>
          <div className={styles.sectionLabel}>
            <i className="fas fa-wave-square" />
            Dòng tiền hôm nay ({fDate(data.asOfDate)})
          </div>
          {cashflowCards}
          <div className={styles.summaryBar}>
            <span className={styles.summaryItem}>
              <label>Số dư cuối ngày dự kiến</label>
              <strong className={data.expectedClosing >= 0 ? styles.summaryPositive : styles.summaryNegative}>
                {fVnd(data.expectedClosing)}
              </strong>
            </span>
            <span className={styles.summaryItem}>
              <label>Chi bắt buộc</label>
              <strong>{fVnd(data.mandatoryPaymentsDue)}</strong>
            </span>
            <span className={styles.summaryItem}>
              <label>Số dư chủ động</label>
              <strong className={data.discretionaryBalance > 0 ? styles.summaryPositive : styles.summaryNegative}>
                {fVnd(data.discretionaryBalance)}
              </strong>
            </span>
          </div>
        </section>
      )}

      {/* ── Charts row ── */}
      <div className={styles.chartsRow}>
        {trendChart ?? (
          <Card padding="md" className={styles.chartCard} data-testid={`${TEST_ID}-trend-chart`}>
            <p style={{ padding: 16, color: '#999' }}>Không có dữ liệu biểu đồ xu hướng</p>
          </Card>
        )}
        {compositionChart ?? (
          <Card padding="md" className={styles.chartCard} data-testid={`${TEST_ID}-composition-chart`}>
            <p style={{ padding: 16, color: '#999' }}>Không có dữ liệu cơ cấu tiền mặt</p>
          </Card>
        )}
      </div>

      {/* ── Middle row: branches ── */}
      {branchSection}

      {/* ── Bottom row: outflows + alerts ── */}
      <div className={styles.bottomRow}>
        <div className={styles.bottomLeft}>
          {topOutflows ?? (
            <TableCard
              header={
                <div className={styles.tableCardHeader}>
                  <h3 className={styles.cardTitle}>Chi nhiều nhất hôm nay</h3>
                </div>
              }
              tableCardTestId={`${TEST_ID}-top-outflows`}
            >
              <p style={{ padding: 16, color: '#999' }}>Không có dữ liệu chi phí</p>
            </TableCard>
          )}
        </div>
        <div className={styles.bottomRight}>
          {alertsCard ?? (
            <Card padding="none" className={styles.alertsCard} data-testid={`${TEST_ID}-alerts`}>
              <div className={styles.alertsCardHeader}>
                <h3 className={styles.cardTitle}>Cảnh báo và thông báo</h3>
              </div>
              <p style={{ padding: 16, color: '#999' }}>Không có cảnh báo</p>
            </Card>
          )}
        </div>
      </div>

      {/* ── Quick Actions ── */}
      <section data-testid={`${TEST_ID}-actions`}>
        {quickActions}
      </section>
    </div>
  );
};

export default CeoCashTodayPage;
